// SearchAtlassianConnect searches the atlassian_connect_fts index with optional filters.
func (s *Store) SearchAtlassianConnect(query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 50
	}
	rows, err := s.db.Query(
		`SELECT t.data FROM atlassian_connect t
		 JOIN atlassian_connect_fts ON atlassian_connect_fts.rowid = t.rowid
		 WHERE atlassian_connect_fts MATCH ?
		 ORDER BY atlassian_connect_fts.rank LIMIT ?`,
		query, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

